import React, { useState, useEffect } from 'react';
import { Globe, ArrowUpRight, Zap } from 'lucide-react';
import useAuth from '../hooks/useAuth';

const LiveMarket = () => {
  const { token } = useAuth();
  const [connectionStatus, setConnectionStatus] = useState('CONNECTING');

  useEffect(() => {
    const socket = new WebSocket(`ws://localhost:8000/ws/pulse?token=${token}`);
    socket.onopen = () => setConnectionStatus('STABLE');
    socket.onclose = () => setConnectionStatus('OFFLINE');
    return () => socket.close();
  }, [token]);

  return (
    <div className="reveal-node" style={{ padding: '2rem', maxWidth: '1200px', margin: '0 auto' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '2rem' }}>
        <div>
          <h2 style={{ color: 'var(--text-primary)', textTransform: 'uppercase', letterSpacing: '0.1em', display: 'flex', alignItems: 'center', gap: '10px' }}>
            <Globe size={20} color="var(--accent-primary)" /> Live_Market_Pulse
          </h2>
          <p style={{ fontSize: '0.6rem', color: 'var(--text-muted)' }}>NODE: PUNE_MAH_IN_01 // SOURCE: YFINANCE_REALTIME</p>
        </div>
        <div style={{ padding: '0.5rem 1rem', borderRadius: '8px', background: connectionStatus === 'STABLE' ? 'rgba(16, 185, 129, 0.1)' : 'rgba(239, 68, 68, 0.1)', color: connectionStatus === 'STABLE' ? 'var(--accent-primary)' : '#ef4444', fontSize: '0.6rem', fontWeight: 800, border: '1px solid currentColor' }}>
          {connectionStatus}
        </div>
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '1rem' }}>
        {['RELIANCE', 'TCS', 'HDFCBANK', 'INFY', 'ICICIBANK'].map((ticker) => (
          <div key={ticker} style={{ padding: '1.5rem', background: 'var(--surface-glass)', border: '1px solid var(--surface-border)', borderRadius: '14px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '1rem' }}>
              <span style={{ fontWeight: 800, color: 'var(--text-primary)' }}>{ticker}</span>
              <Zap size={14} color="var(--accent-primary)" />
            </div>
            <div style={{ fontSize: '1.2rem', fontWeight: 800, color: 'var(--text-primary)' }}>
              ₹{(2500 + Math.random() * 100).toFixed(2)}
            </div>
            <div style={{ fontSize: '0.6rem', color: '#10b981', display: 'flex', alignItems: 'center', gap: '4px' }}>
              <ArrowUpRight size={10} /> +1.24%
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};

export default LiveMarket;
